from cryptography.fernet import Fernet
import base64
import os

def generate_key():
    return Fernet.generate_key()

def encrypt_credit_card_number(credit_card_number, secret_key):
    f = Fernet(secret_key)
    encrypted_credit_card_number = f.encrypt(credit_card_number.encode())
    return encrypted_credit_card_number

def decrypt_credit_card_number(encrypted_credit_card_number, secret_key):
    f = Fernet(secret_key)
    decrypted_credit_card_number = f.decrypt(encrypted_credit_card_number).decode()
    return decrypted_credit_card_number

# Usage
secret_key = os.environ.get('SECRET_KEY')
if not secret_key:
    secret_key = generate_key()

